-- BEGIN TABLE public.bytedesk_ai_prompt
DROP TABLE IF EXISTS public.bytedesk_ai_prompt CASCADE;
BEGIN;

CREATE TABLE IF NOT EXISTS public.bytedesk_ai_prompt (
	id bigint GENERATED BY DEFAULT AS IDENTITY NOT NULL,
	created_at timestamp(6) with time zone GENERATED BY DEFAULT AS IDENTITY,
	is_deleted boolean GENERATED BY DEFAULT AS IDENTITY,
	level_type character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	org_uid character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	platform_type character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	uuid character varying(255) GENERATED BY DEFAULT AS IDENTITY NOT NULL,
	updated_at timestamp(6) with time zone GENERATED BY DEFAULT AS IDENTITY,
	user_uid character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	"version" integer GENERATED BY DEFAULT AS IDENTITY NOT NULL,
	description character varying(512) GENERATED BY DEFAULT AS IDENTITY,
	is_enabled boolean GENERATED BY DEFAULT AS IDENTITY NOT NULL,
	"language" character varying(16) GENERATED BY DEFAULT AS IDENTITY,
	metadata text GENERATED BY DEFAULT AS IDENTITY,
	name character varying(128) GENERATED BY DEFAULT AS IDENTITY NOT NULL,
	nickname character varying(128) GENERATED BY DEFAULT AS IDENTITY,
	optimization_metadata text GENERATED BY DEFAULT AS IDENTITY,
	optimized_prompt text GENERATED BY DEFAULT AS IDENTITY,
	score_result text GENERATED BY DEFAULT AS IDENTITY,
	system_prompt text GENERATED BY DEFAULT AS IDENTITY,
	tags text GENERATED BY DEFAULT AS IDENTITY,
	prompt_type character varying(32) GENERATED BY DEFAULT AS IDENTITY NOT NULL,
	user_prompt text GENERATED BY DEFAULT AS IDENTITY,
	variables text GENERATED BY DEFAULT AS IDENTITY,
	PRIMARY KEY(id)
);

COMMIT;

