-- BEGIN TABLE public.bytedesk_ai_provider
DROP TABLE IF EXISTS public.bytedesk_ai_provider CASCADE;
BEGIN;

CREATE TABLE IF NOT EXISTS public.bytedesk_ai_provider (
	id bigint GENERATED BY DEFAULT AS IDENTITY NOT NULL,
	created_at timestamp(6) with time zone GENERATED BY DEFAULT AS IDENTITY,
	is_deleted boolean GENERATED BY DEFAULT AS IDENTITY,
	level_type character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	org_uid character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	platform_type character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	uuid character varying(255) GENERATED BY DEFAULT AS IDENTITY NOT NULL,
	updated_at timestamp(6) with time zone GENERATED BY DEFAULT AS IDENTITY,
	user_uid character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	"version" integer GENERATED BY DEFAULT AS IDENTITY NOT NULL,
	api_key character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	base_url character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	coze_bot_id character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	description character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	is_enabled boolean GENERATED BY DEFAULT AS IDENTITY,
	logo character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	nickname character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	ragflow_id character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	ragflow_type character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	status character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	is_system_enabled boolean GENERATED BY DEFAULT AS IDENTITY,
	provider_type character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	web_url character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	PRIMARY KEY(id)
);

COMMIT;

