-- BEGIN TABLE public.bytedesk_ai_robot
DROP TABLE IF EXISTS public.bytedesk_ai_robot CASCADE;
BEGIN;

CREATE TABLE IF NOT EXISTS public.bytedesk_ai_robot (
	id bigint GENERATED BY DEFAULT AS IDENTITY NOT NULL,
	created_at timestamp(6) with time zone GENERATED BY DEFAULT AS IDENTITY,
	is_deleted boolean GENERATED BY DEFAULT AS IDENTITY,
	level_type character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	org_uid character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	platform_type character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	uuid character varying(255) GENERATED BY DEFAULT AS IDENTITY NOT NULL,
	updated_at timestamp(6) with time zone GENERATED BY DEFAULT AS IDENTITY,
	user_uid character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	"version" integer GENERATED BY DEFAULT AS IDENTITY NOT NULL,
	avatar character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	category_uid character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	description character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	is_kb_enabled boolean GENERATED BY DEFAULT AS IDENTITY,
	is_kb_source_enabled boolean GENERATED BY DEFAULT AS IDENTITY,
	kb_uid character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	is_audio_enabled boolean GENERATED BY DEFAULT AS IDENTITY,
	llm_audio_model character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	llm_audio_provider character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	llm_audio_provider_uid character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	llm_context_msg_count integer GENERATED BY DEFAULT AS IDENTITY,
	default_reply character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	llm_do_sample boolean GENERATED BY DEFAULT AS IDENTITY,
	is_search_enabled boolean GENERATED BY DEFAULT AS IDENTITY,
	is_streaming_enabled boolean GENERATED BY DEFAULT AS IDENTITY,
	is_thinking_enabled boolean GENERATED BY DEFAULT AS IDENTITY,
	is_llm_enabled boolean GENERATED BY DEFAULT AS IDENTITY,
	llm_max_tokens integer GENERATED BY DEFAULT AS IDENTITY,
	llm_prompt text GENERATED BY DEFAULT AS IDENTITY,
	llm_request_id character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	is_rerank_enabled boolean GENERATED BY DEFAULT AS IDENTITY,
	llm_rerank_model character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	llm_rerank_provider character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	llm_rerank_provider_uid character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	llm_response_format character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	llm_rewrite_enabled boolean GENERATED BY DEFAULT AS IDENTITY,
	llm_rewrite_model character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	llm_rewrite_prompt text GENERATED BY DEFAULT AS IDENTITY,
	llm_rewrite_provider character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	llm_rewrite_provider_uid character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	llm_score_threshold double precision GENERATED BY DEFAULT AS IDENTITY,
	llm_search_type character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	llm_stops character varying(255)[] GENERATED BY DEFAULT AS IDENTITY,
	llm_temperature double precision GENERATED BY DEFAULT AS IDENTITY,
	llm_text_model character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	llm_text_provider character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	llm_text_provider_uid character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	llm_tool_choice character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	llm_tools character varying(255)[] GENERATED BY DEFAULT AS IDENTITY,
	llm_top_k integer GENERATED BY DEFAULT AS IDENTITY,
	llm_top_p double precision GENERATED BY DEFAULT AS IDENTITY,
	llm_use_when_kb_empty boolean GENERATED BY DEFAULT AS IDENTITY,
	llm_user_id character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	name character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	nickname character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	is_system boolean GENERATED BY DEFAULT AS IDENTITY,
	robot_type character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	settings_id bigint GENERATED BY DEFAULT AS IDENTITY,
	PRIMARY KEY(id)
);

COMMIT;

