	channel character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	"content" text GENERATED BY DEFAULT AS IDENTITY,
	extra text GENERATED BY DEFAULT AS IDENTITY,
	status character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	message_type character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	message_user character varying(2048) GENERATED BY DEFAULT AS IDENTITY,
	accuracy double precision GENERATED BY DEFAULT AS IDENTITY,
	ai_model character varying(100) GENERATED BY DEFAULT AS IDENTITY,
	ai_provider character varying(50) GENERATED BY DEFAULT AS IDENTITY,
	answer text GENERATED BY DEFAULT AS IDENTITY,
	completion_tokens integer GENERATED BY DEFAULT AS IDENTITY,
