	thread_uid character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	thread_topic character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	total_tokens integer GENERATED BY DEFAULT AS IDENTITY,
	PRIMARY KEY(id)
);

COMMIT;

