	id bigint GENERATED BY DEFAULT AS IDENTITY NOT NULL,
	created_at timestamp(6) with time zone GENERATED BY DEFAULT AS IDENTITY,
	is_deleted boolean GENERATED BY DEFAULT AS IDENTITY,
	level_type character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	org_uid character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	platform_type character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	uuid character varying(255) GENERATED BY DEFAULT AS IDENTITY NOT NULL,
	updated_at timestamp(6) with time zone GENERATED BY DEFAULT AS IDENTITY,
	user_uid character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	"version" integer GENERATED BY DEFAULT AS IDENTITY NOT NULL,
	confidence_threshold double precision GENERATED BY DEFAULT AS IDENTITY,
	is_default_template boolean GENERATED BY DEFAULT AS IDENTITY,
	settings_description character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	enable_intention_tracking boolean GENERATED BY DEFAULT AS IDENTITY,
	is_enabled boolean GENERATED BY DEFAULT AS IDENTITY,
	execution_timing character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	intention_list text GENERATED BY DEFAULT AS IDENTITY,
	intention_priorities text GENERATED BY DEFAULT AS IDENTITY,
	intention_responses text GENERATED BY DEFAULT AS IDENTITY,
	intention_switch_threshold double precision GENERATED BY DEFAULT AS IDENTITY,
	intention_intention_settingss text GENERATED BY DEFAULT AS IDENTITY,
	settings_name character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	robot_uid character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	sub_intention_mapping text GENERATED BY DEFAULT AS IDENTITY,
	is_trigger_cooldown_only boolean GENERATED BY DEFAULT AS IDENTITY,
	trigger_cooldown_seconds integer GENERATED BY DEFAULT AS IDENTITY,
	trigger_every_n_messages integer GENERATED BY DEFAULT AS IDENTITY,
	trigger_scope character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	unknown_intention_handling character varying(255) GENERATED BY DEFAULT AS IDENTITY,
	unknown_intention_response text GENERATED BY DEFAULT AS IDENTITY,
	PRIMARY KEY(id)
);

COMMIT;

